import { Bar } from 'react-chartjs-2';
import {
  Chart as ChartJS, CategoryScale, LinearScale, BarElement, Tooltip, Legend
} from 'chart.js';

ChartJS.register(CategoryScale, LinearScale, BarElement, Tooltip, Legend);

function Charts({ transactions }) {
  if (transactions.length === 0) return null;

  const totalIncome  = transactions.filter(t => t.type === 'income').reduce((s, t) => s + t.amount, 0);
  const totalExpense = transactions.filter(t => t.type === 'expense').reduce((s, t) => s + t.amount, 0);

  const expenses   = transactions.filter(t => t.type === 'expense');
  const categories = [...new Set(expenses.map(t => t.category))];
  const catTotals  = categories.map(cat =>
    expenses.filter(t => t.category === cat).reduce((s, t) => s + t.amount, 0)
  );

  return (
    <div className="charts">
      <h3>Income vs Expense</h3>
      <Bar data={{
        labels: ['Income', 'Expense'],
        datasets: [{ label: '₹', data: [totalIncome, totalExpense], backgroundColor: ['#16a34a', '#dc2626'] }]
      }} />

      {categories.length > 0 && (
        <>
          <h3>Expense by Category</h3>
          <Bar data={{
            labels: categories,
            datasets: [{ label: '₹', data: catTotals, backgroundColor: '#2563eb' }]
          }} />
        </>
      )}
    </div>
  );
}

export default Charts;